			buffer.positionCursor(1, 0)

			buffer.eraseScreenToEnd()

			assertAll(
				{ assertEquals("A", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) },
				{ assertEquals("", buffer.getLineAsString(2)) }
			)
		}

		@Test
		fun `eraseScreenToEnd at home clears entire screen`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.positionCursor(0, 0)

			buffer.eraseScreenToEnd()

			assertAll(
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) }
			)
		}

		@Test
		fun `eraseScreenToEnd at end clears only last cell`() {
			val buffer = newBuffer(width = 2, height = 3, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.positionCursor(1, 1)

			buffer.eraseScreenToEnd()

			assertAll(
				{ assertEquals("AB", buffer.getLineAsString(0)) },
				{ assertEquals("C", buffer.getLineAsString(1)) },
				{ assertEquals("", buffer.getLineAsString(2)) }
			)
		}

		@Test
		fun `eraseScreenToEnd uses current pen attribute`() {
			val buffer = newBuffer(width = 3, height = 3, maxHistory = 0)
			buffer.writeText("ABCDEF")
			buffer.setPenAttributes(fg = 2, bg = 3, bold = true)
			buffer.positionCursor(1, 0)

			buffer.eraseScreenToEnd()

			val clearAttr = Attributes(2, 3, bold = true, italic = false, underline = false)
			assertAll(
				{ assertEquals('A'.code, buffer.getCodepointAt(0, 0)) },
				{ assertEquals(TerminalConstants.EMPTY, buffer.getCodepointAt(1, 0)) },
				{ assertEquals(clearAttr, buffer.getAttrAt(1, 0)) },
				{ assertEquals(clearAttr, buffer.getAttrAt(0, 1)) }
			)
		}

		@Test
		fun `eraseScreenToEnd does not move cursor`() {
			val buffer = newBuffer(width = 4, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.positionCursor(2, 1)

			buffer.eraseScreenToEnd()

			assertCursor(buffer, 2, 1)
		}

		@Test
		fun `eraseScreenToCursor clears from start of screen through cursor`() {
			val buffer = newBuffer(width = 3, height = 4, maxHistory = 0)
			buffer.writeText("ABCDEFGHI")
			buffer.positionCursor(1, 1)

			buffer.eraseScreenToCursor()

			assertAll(
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("  F", buffer.getLineAsString(1)) },
				{ assertEquals("GHI", buffer.getLineAsString(2)) }
			)
		}

		@Test
		fun `eraseScreenToCursor at home clears only home cell`() {
			val buffer = newBuffer(width = 2, height = 3, maxHistory = 0)
			buffer.writeText("ABCD")
			// rows: "AB" / "CD" / "" — no scroll occurred
			buffer.positionCursor(0, 0)

			buffer.eraseScreenToCursor()

			assertAll(
				{ assertEquals(" B", buffer.getLineAsString(0)) },
				{ assertEquals("CD", buffer.getLineAsString(1)) }
			)
		}

		@Test
		fun `eraseScreenToCursor at end clears entire screen`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.positionCursor(1, 1)

			buffer.eraseScreenToCursor()

			assertAll(
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) }
			)
		}

		@Test
		fun `eraseScreenToCursor uses current pen attribute`() {
			val buffer = newBuffer(width = 3, height = 2, maxHistory = 0)
			buffer.writeText("ABCDEF") // Row 0="ABC", Row 1="DEF"
			buffer.setPenAttributes(fg = 5, bg = 1, italic = true)

			buffer.positionCursor(1, 1) // Moves to 'E'. pendingWrap cleared.
			buffer.eraseScreenToCursor()

			val clearAttr = Attributes(5, 1, bold = false, italic = true, underline = false)
			assertAll(
				// Row 0 is fully erased
				{ assertEquals(clearAttr, buffer.getAttrAt(0, 0)) },
				{ assertEquals(clearAttr, buffer.getAttrAt(1, 0)) },
				// Row 1 is erased up to col 1. Col 2 ('F') remains untouched.
				{ assertEquals('F'.code, buffer.getCodepointAt(2, 1)) },
				{ assertEquals(clearAttr, buffer.getAttrAt(1, 1)) },
				{ assertEquals(TerminalConstants.EMPTY, buffer.getCodepointAt(1, 1)) }
			)
		}

		@Test
		fun `eraseScreenToCursor does not move cursor`() {
			val buffer = newBuffer(width = 4, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.positionCursor(1, 0)

			buffer.eraseScreenToCursor()

			assertCursor(buffer, 1, 0)
		}

		@Test
		fun `eraseScreenToEnd and eraseScreenToCursor with history preserved`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 4)
			buffer.writeText("ABCDEF")

			// 3 lines: "AB" in history, "CD", "EF" on screen.
			assertEquals(1, buffer.historySize)

			buffer.positionCursor(0, 0)
			buffer.eraseScreenToEnd()

			// History should be untouched
			assertEquals(1, buffer.historySize)
			assertEquals("", buffer.getLineAsString(0))
			assertEquals("", buffer.getLineAsString(1))
		}

		@Test
		fun `eraseEntireScreen clears entire visible screen without moving cursor`() {
			val buffer = newBuffer(width = 3, height = 3, maxHistory = 0)
			buffer.writeText("ABCDEFGHI")
			buffer.positionCursor(1, 1)
			buffer.setPenAttributes(fg = 2, bg = 3, bold = true)

			buffer.eraseEntireScreen()

			assertAll(
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) },
				{ assertEquals("", buffer.getLineAsString(2)) },
				{ assertCursor(buffer, 1, 1) }
			)
		}

		@Test
		fun `eraseEntireScreen uses current pen attribute`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.setPenAttributes(fg = 4, bg = 5, italic = true, underline = true)

			buffer.eraseEntireScreen()

			val clearAttr = Attributes(4, 5, bold = false, italic = true, underline = true)
			assertAll(
				{ assertEquals(clearAttr, buffer.getAttrAt(0, 0)) },
				{ assertEquals(clearAttr, buffer.getAttrAt(1, 1)) },
				{ assertEquals(TerminalConstants.EMPTY, buffer.getCodepointAt(0, 0)) }
			)
		}

		@Test
		fun `eraseEntireScreen preserves history`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 4)
			buffer.writeText("ABCD")
			// History: "AB", Screen: "CD"
			val historyBefore = buffer.historySize

			buffer.eraseEntireScreen()

			assertAll(
				{ assertEquals(historyBefore, buffer.historySize) },
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) }
			)
		}

		@Test
		fun `eraseEntireScreen at all cursor positions`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")

			// Test at home
			buffer.positionCursor(0, 0)
			buffer.eraseEntireScreen()
			assertAll(
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertCursor(buffer, 0, 0) }
			)

			// Refill and test at end
			buffer.writeText("ABCD")
			buffer.positionCursor(1, 1)
			buffer.eraseEntireScreen()
			assertAll(
				{ assertEquals("", buffer.getLineAsString(1)) },
				{ assertCursor(buffer, 1, 1) }
			)
		}

		@Test
		fun `eraseScreenAndHistory clears screen, history, and leaves cursor unchanged`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 4)
			buffer.writeText("ABCDEF")
			// History: "AB"; Screen: "CD", "EF"
			assertEquals(1, buffer.historySize)
			buffer.positionCursor(1, 1)

			buffer.eraseScreenAndHistory()

			assertAll(
				{ assertEquals(0, buffer.historySize) },
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) },
				{ assertCursor(buffer, 1, 1) }
			)
		}

		@Test
		fun `eraseScreenAndHistory uses current pen attribute`() {
			val buffer = newBuffer(width = 3, height = 2, maxHistory = 2)
			buffer.writeText("ABCDEF")
			buffer.setPenAttributes(fg = 1, bg = 6, bold = true, underline = true)

			buffer.eraseScreenAndHistory()

			val clearAttr = Attributes(1, 6, bold = true, italic = false, underline = true)
			assertAll(
				{ assertEquals(clearAttr, buffer.getAttrAt(0, 0)) },
				{ assertEquals(clearAttr, buffer.getAttrAt(2, 1)) },
				{ assertEquals(TerminalConstants.EMPTY, buffer.getCodepointAt(0, 0)) }
			)
		}

		@Test
		fun `eraseScreenAndHistory with zero history`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 0)
			buffer.writeText("ABCD")
			buffer.positionCursor(0, 0)

			buffer.eraseScreenAndHistory()

			assertAll(
				{ assertEquals(0, buffer.historySize) },
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) },
				{ assertCursor(buffer, 0, 0) }
			)
		}

		@Test
		fun `eraseScreenAndHistory at various cursor positions`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 3)
			buffer.writeText("ABCDE")

			// Test at home
			buffer.positionCursor(0, 0)
			buffer.eraseScreenAndHistory()
			assertAll(
				{ assertEquals(0, buffer.historySize) },
				{ assertCursor(buffer, 0, 0) }
			)

			// Refill and test at bottom-right
			buffer.writeText("ABCDE")
			buffer.positionCursor(1, 1)
			buffer.eraseScreenAndHistory()
			assertAll(
				{ assertEquals(0, buffer.historySize) },
				{ assertCursor(buffer, 1, 1) }
			)
		}

		@Test
		fun `eraseScreenAndHistory completely clears a large scrollback`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 20)
			// Fill up a lot of history
			repeat(15) {
				buffer.writeText("AB")
				buffer.newLine()
			}
			val historyAfterWrite = buffer.historySize
			assertTrue(historyAfterWrite > 10, "Should have significant history")

			buffer.eraseScreenAndHistory()

			assertAll(
				{ assertEquals(0, buffer.historySize) },
				{ assertEquals("", buffer.getLineAsString(0)) },
				{ assertEquals("", buffer.getLineAsString(1)) }
			)
		}
	}

	@Nested
	@DisplayName("Resize")
	inner class ResizeTests {

		@Test
		fun `resize is exposed through the public API`() {
			val buffer = newApiBuffer(width = 4, height = 2, maxHistory = 3)
			buffer.writeText("ABCD")

			buffer.resize(newWidth = 2, newHeight = 3)

			assertAll(
				{ assertEquals(2, buffer.width) },
				{ assertEquals(3, buffer.height) },
				{ assertTrue(buffer.cursorCol in 0 until buffer.width) },
				{ assertTrue(buffer.cursorRow in 0 until buffer.height) }
			)
		}

		@Test
		fun `resize rejects non-positive dimensions through the public API`() {
			val buffer = newApiBuffer()

			assertThrows<IllegalArgumentException> { buffer.resize(0, 2) }
			assertThrows<IllegalArgumentException> { buffer.resize(2, 0) }
			assertThrows<IllegalArgumentException> { buffer.resize(-1, 2) }
			assertThrows<IllegalArgumentException> { buffer.resize(2, -1) }
		}
	}

	@Nested
	@DisplayName("Rendering & Query API")
	inner class RenderingTests {

		@Test
		fun `getLine provides a read-only view of a row`() {
			val buffer = newBuffer(width = 5, height = 2)
			buffer.writeText("HELLO")
			buffer.setPenAttributes(fg = 1, bg = 2, bold = true)

			val line = buffer.getLine(0)
			assertEquals(5, line.width)
			assertEquals('H'.code, line.getCodepoint(0))
			assertEquals('O'.code, line.getCodepoint(4))

			val line2 = buffer.getLine(1)
			assertEquals(0, line2.getCodepoint(0))
		}

		@Test
		fun `getLine returns a VoidLine for out of bounds rows`() {
			val buffer = newBuffer(width = 5, height = 2)

			val outOfBounds1 = buffer.getLine(-1)
			assertEquals(0, outOfBounds1.width)
			assertEquals(TerminalConstants.EMPTY, outOfBounds1.getCodepoint(0))
			assertEquals(0, outOfBounds1.getPackedAttr(0))

			val outOfBounds2 = buffer.getLine(2)
			assertEquals(0, outOfBounds2.width)

			val outOfBounds3 = buffer.getLine(99)
			assertEquals(0, outOfBounds3.width)
		}

		@Test
		fun `getCodepointAt getPackedAttrAt and getAttrAt honor valid and invalid coordinates`() {
			val buffer = newBuffer(width = 4, height = 2)

			buffer.setPenAttributes(2, 3, bold = true, underline = true)
			buffer.writeCodepoint('Q'.code)
			val expectedAttr = buffer.getPackedAttrAt(0, 0)

			assertAll(
				{ assertEquals('Q'.code, buffer.getCodepointAt(0, 0)) },
				{ assertEquals(expectedAttr, buffer.getPackedAttrAt(0, 0)) },
				{ assertEquals(Attributes(2, 3, true, false, true), buffer.getAttrAt(0, 0)) },
				{ assertEquals(TerminalConstants.EMPTY, buffer.getCodepointAt(-1, 0)) },
				{ assertEquals(TerminalConstants.EMPTY, buffer.getCodepointAt(0, -1)) },
				{ assertEquals(expectedAttr, buffer.getPackedAttrAt(-1, 0)) },
				{ assertEquals(expectedAttr, buffer.getPackedAttrAt(0, 99)) },
				{ assertNull(buffer.getAttrAt(-1, 0)) },
				{ assertNull(buffer.getAttrAt(99, 99)) }
			)
		}

		@Test
		fun `getLineAsString trims trailing empty cells but preserves leading and internal spaces`() {
			val buffer = newBuffer(width = 10, height = 1)
			buffer.writeText("  A  ")

			assertEquals("  A  ", buffer.getLineAsString(0))

			buffer.clearScreen()
			buffer.writeText("ABC")
			assertEquals("ABC", buffer.getLineAsString(0))
		}

		@Test
		fun `getLineAsString with only empty cells returns empty string`() {
			val buffer = newBuffer(width = 5, height = 1)
			assertEquals("", buffer.getLineAsString(0))
		}

		@Test
		fun `getLineAsString with only spaces returns spaces`() {
			val buffer = newBuffer(width = 5, height = 1)
			buffer.writeText("   ")
			assertEquals("   ", buffer.getLineAsString(0))
		}

		@Test
		fun `getScreenAsString joins visible rows with newlines`() {
			val buffer = newBuffer(width = 2, height = 3, maxHistory = 0)

			buffer.writeText("ABCD")

			assertAll(
				{ assertEquals("AB\nCD\n", buffer.getScreenAsString()) },
				{ assertEquals("AB\nCD\n", buffer.getAllAsString()) }
			)
		}

		@Test
		fun `getAllAsString includes scrollback before the visible screen`() {
			val buffer = newBuffer(width = 2, height = 2, maxHistory = 2)

			buffer.writeText("ABCDEF") // 1 line in history ("AB"). Screen: "CD", "EF"

			assertAll(
				{ assertEquals(1, buffer.historySize) },
				{ assertEquals("CD\nEF", buffer.getScreenAsString()) },
				{ assertEquals("AB\nCD\nEF", buffer.getAllAsString()) }
			)
		}
	}
}

package com.gagik.terminal.buffer

import com.gagik.terminal.TerminalBuffers
import com.gagik.terminal.api.TerminalBufferApi
import com.gagik.terminal.model.Attributes
import org.junit.jupiter.api.Assertions.assertAll
import org.junit.jupiter.api.Assertions.assertEquals
import org.junit.jupiter.api.Assertions.assertThrows
import org.junit.jupiter.api.DisplayName
import org.junit.jupiter.api.Test

@DisplayName("TerminalBuffer Integration Test Suite")
class TerminalBufferTest {

	private fun newBuffer(width: Int = 4, height: Int = 3, maxHistory: Int = 5): TerminalBuffer {
		return TerminalBuffer(width, height, maxHistory)
	}

	private fun newApiBuffer(width: Int = 4, height: Int = 3, maxHistory: Int = 5): TerminalBufferApi {
		return TerminalBuffers.create(width, height, maxHistory)
	}

	private fun blankScreen(height: Int): String = List(height) { "" }.joinToString("\n")

	@Test
	fun `constructs a blank buffer and factory returns a working api surface`() {
		val buffer = newBuffer(width = 3, height = 2, maxHistory = 4)
		val api = newApiBuffer(width = 3, height = 2, maxHistory = 4)

		assertAll(
			{ assertEquals(3, buffer.width) },
			{ assertEquals(2, buffer.height) },
			{ assertEquals(0, buffer.cursorCol) },
			{ assertEquals(0, buffer.cursorRow) },
			{ assertEquals(0, buffer.historySize) },
			{ assertEquals(blankScreen(2), buffer.getScreenAsString()) },
			{ assertEquals(blankScreen(2), buffer.getAllAsString()) },
			{ assertEquals(3, api.width) },
			{ assertEquals(2, api.height) },
			{ assertEquals(blankScreen(2), api.getScreenAsString()) }
		)
	}

	@Test
	fun `constructor and factory reject invalid dimensions`() {
		assertThrows<IllegalArgumentException> { TerminalBuffer(0, 1) }
		assertThrows<IllegalArgumentException> { TerminalBuffers.create(1, 0) }
	}

	@Test
	fun `saveCursor and restoreCursor round-trip cursor and pen state through the facade`() {
		val buffer = newApiBuffer(width = 4, height = 3)
		buffer.positionCursor(2, 1)
		buffer.setPenAttributes(3, 7, bold = true, italic = true, underline = false)

		buffer.saveCursor()
		buffer.positionCursor(0, 0)
		buffer.setPenAttributes(1, 2, bold = false, italic = false, underline = true)
		buffer.restoreCursor()

		assertAll(
			{ assertEquals(2, buffer.cursorCol) },
			{ assertEquals(1, buffer.cursorRow) }
		)

		buffer.writeCodepoint('X'.code)

		assertAll(
			{ assertEquals(3, buffer.cursorCol) },
			{ assertEquals(1, buffer.cursorRow) },
			{ assertEquals('X'.code, buffer.getCodepointAt(2, 1)) },
			{ assertEquals(Attributes(3, 7, bold = true, italic = true, underline = false), buffer.getAttrAt(2, 1)) }
		)
	}

	@Test
	fun `resize and reset remain coordinated through the TerminalBuffer facade`() {
		val buffer = newApiBuffer(width = 4, height = 2, maxHistory = 3)
		buffer.writeText("ABCD")
		buffer.resize(newWidth = 2, newHeight = 3)

		assertAll(
			{ assertEquals(2, buffer.width) },
			{ assertEquals(3, buffer.height) },
			{ assertEquals("AB\nCD\n", buffer.getScreenAsString()) },
			{ assertEquals(true, buffer.cursorCol in 0 until buffer.width) },
			{ assertEquals(true, buffer.cursorRow in 0 until buffer.height) }
		)

		buffer.reset()

		assertAll(
			{ assertEquals(2, buffer.width) },
			{ assertEquals(3, buffer.height) },
			{ assertEquals(blankScreen(3), buffer.getScreenAsString()) },
			{ assertEquals(blankScreen(3), buffer.getAllAsString()) },
			{ assertEquals(0, buffer.cursorCol) },
			{ assertEquals(0, buffer.cursorRow) }
		)
	}
}

package com.gagik.terminal.buffer.impl

import com.gagik.terminal.api.TerminalInspector
import com.gagik.terminal.codec.AttributeCodec
import com.gagik.terminal.model.Attributes
import com.gagik.terminal.model.Line
import com.gagik.terminal.model.TerminalConstants
import com.gagik.terminal.state.TerminalState

internal class TerminalInspectorImpl(
	private val state: TerminalState
) : TerminalInspector {

	override fun getAttrAt(col: Int, row: Int): Attributes? {
		if (!state.dimensions.isValidCol(col) || !state.dimensions.isValidRow(row)) return null
		val line = visibleLine(row) ?: return null
		val rawAttr = if (line.width == 0) state.pen.currentAttr else line.getPackedAttr(col)
		return AttributeCodec.unpack(rawAttr)
	}

	override fun getLineAsString(row: Int): String {
		return visibleLine(row)?.toTextTrimmed() ?: ""
	}

	override fun getScreenAsString(): String = buildString {
		for (row in 0 until state.dimensions.height) {
			if (row > 0) append('\n')
			append(getLineAsString(row))
		}
	}

	override fun getAllAsString(): String {
		val sb = StringBuilder()
		for (row in 0 until state.ring.size) {
			if (row > 0) sb.append('\n')
			sb.append(state.ring[row].toTextTrimmed())
		}
		return sb.toString()
	}

	private fun visibleLine(row: Int): Line? {
		if (!state.dimensions.isValidRow(row)) return null
		return state.ring[state.resolveRingIndex(row)]
	}
}

